def json_path_lookup(d, path):
    """Return the value at the given dotted path in nested dict d, or None if not found."""
    if not isinstance(d, dict) or not path:
        return None
    keys = path.split('.')
    current = d
    for key in keys:
        if isinstance(current, dict) and key in current:
            current = current[key]
        else:
            return None
    return current
